VALUES
  ('heelevel3-5ff21eeb-moex-00014', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '受有概括委任之受任人，為下列何種行為，不須有委任人之特別授權？', '["設定土地之普通抵押權", "贈與動產", "訂立二年之房屋租約", "訂立和解契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00015', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲將其所有之A屋出租於乙後，乙將其對A屋之租賃權讓與丙，並通知甲該情事。下列敘述，何 者正確？', '["如甲、乙間並無禁止轉讓之特約，乙之租賃權性質上並非不得讓與之債權", "如乙未能取得甲之同意移轉租賃權時，乙對丙應負債務不履行責任", "丙得以已通知甲關於A屋租賃權之讓與事實，主張其受讓對甲發生效力", "乙、丙就使用A屋而應給付與甲之租金，負連帶責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00016', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲請乙大幅翻修其房屋，約定由甲供給材料，乙為其施作，完工後給付報酬若干。乙明知甲所提 供之材料有問題，足以發生重大瑕疵，卻故意不告知甲，又以特約免除乙修繕房屋之瑕疵擔保義 務。乙嗣於民國（下同）103年1月5日完工，甲於112年4月20日始發現瑕疵，旋即通知乙， 並於113年5月1日定相當期限訴請乙修補瑕疵。對此，乙主張其不負物之瑕疵擔保義務，甲又 已罹於瑕疵發見期間，甲並已逾越權利行使期間等語，以資抗辯。下列敘述，何者正確？', '["因有問題之材料，係由甲所提供，故甲無定相當期限請求乙修補瑕疵之權利", "免除乙修繕房屋之瑕疵擔保義務之特約，為有效", "甲發現瑕疵時，已罹於5年之瑕疵發見期間，故甲不得主張定相當期限請求乙修補瑕疵之權利", "乙提出甲訴請乙修補瑕疵已逾越權利行使期間之抗辯，屬有理由 22420"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00017', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲將自己所有之A屋出售於乙，雙方約定簽約1個月後交屋，交屋後10日內辦妥所有權移轉登 記。下列敘述，何者錯誤？', '["A屋交付於乙後，危險負擔即移轉於乙", "A屋移轉登記於乙之前，即使已經交付，乙仍未取得A屋之所有權，故乙不得承受A屋之利益", "甲乙得於買賣契約中約定，A屋之利益及危險，自A屋之所有權移轉登記於乙時，由乙承受及 負擔", "甲對於乙，應擔保A屋交付於乙時，無滅失或減少其價值之瑕疵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00018', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲向乙購買A藝術品，約定價金新臺幣（下同）10萬元，並由乙於翌日早上11點送貨到甲宅。 乙隔天囑咐其員工丙開車於約定時間送至甲宅，詎甲非因過失確診罹患重症昏迷，被送進加護病 房，而不在家。丙久候多時，又聯絡不上甲，只好將A藝術品運回。回程途中，貨車司機丁因酒 駕而追撞丙車，丙身受重傷，其運送之A藝術品因碰撞滅失。下列敘述，何者錯誤？', '["丙就其遭撞受重傷一事，不得向無過失之乙請求賠償", "乙得向甲請求支付價金10萬元", "甲於支付價金時，得向乙請求讓與其對丁之侵權行為損害賠償請求權", "甲非因過失而受領遲延，仍負受領遲延責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00019', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '出租人甲將自己所有之A屋，口頭與乙約定以每月租金新臺幣（下同）3萬元出租於乙。甲乙間 關於A屋之租賃契約，下列敘述，何者正確？', '["若甲與乙僅以口頭約定租期為30年，則甲乙間之租賃契約期限縮短為20年", "若甲與乙僅以口頭約定租期為3個月，則租賃期限屆滿後，乙仍為租賃物之使用收益，而甲不 即表示反對之意思者，視為合意更新租賃契約。更新後之租賃契約，期間仍為3個月", "若甲與乙僅以口頭約定租期為3個月，但甲一開始即言明，期滿後絕不續租，則3個月之租賃 期限屆滿後，縱使乙仍為租賃物之使用收益，亦不發生租賃契約默示更新之效果，租賃契約因 期間屆滿而終了", "若甲與乙僅以口頭約定租期為30年，則甲乙間之租賃契約無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00020', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '稱普通抵押權者，謂債權人對於債務人或第三人不移轉占有而供其債權擔保之不動產，得就該不 動產賣得價金優先受償之權。下列何者，不為普通抵押權效力所及？', '["以建築物為抵押者，其附加於該建築物，具獨立性之部分", "抵押物之從物", "抵押物扣押後，自抵押物分離，而得由抵押人收取之天然孳息", "抵押物滅失後之殘餘物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00021', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列何者不得辦理登記以對抗第三人？', '["不動產共有人關於共有物之使用管理約定", "地上權之預付地租", "區分地上權人與其設定之土地上下有使用收益權利之人，相互間關於使用收益之限制約定", "不動產共有人關於應有部分轉讓之限制約定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00022', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '21歲獨子乙趁甲父病重，將甲所有之傳家A鑽戒變賣於惡意丙，為避免被發現，乙、丙間約定以 占有改定方式交付，甲得知此事後氣絕身亡，由乙唯一繼承甲之財產。乙欲將A鑽戒再次交付於 丙，因丙暫時出國，雙方商量後約定委託丁轉交。此時A鑽戒所有權之歸屬？', '["甲", "乙", "丙", "丁 22420"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00023', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於普通地上權存續期間規定之敘述，何者正確？', '["定有期限之地上權，為達土地利用目的，其存續期間不得低於一年以下", "定有期限之地上權，其存續期間逾三十年者，縮短為三十年", "未定有期限之地上權，其存續期間逾二十年者，當事人一方得自行終止其地上權", "未定有期限之地上權，如係以公共建設為目的而成立者，以該建設使用目的完畢時，視為地上 權之存續期限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
